mv -n '/btrfs/volume1/mac/Art Library/a.txt' '/btrfs/volume1/mac/Art Library/a.txt.old' || { echo "FAILED to rename: $src"; exit 1; }
[ -e "$src" ] && { echo "FAILED: destination appeared concurrently; nothing was moved"; exit 1; }
echo "Renamed successfully"

